import java.awt.Color;
import org.jfree.data.Range;

public class GrayPaintScale extends AbstractPaintScale {
   private static final long serialVersionUID = 1L;
   public Range domain;
   public int lowerBound;
   public int upperBound;

   public GrayPaintScale(String id) {
      super(id);
   }

   public void setDomain(Range range){
       if(range != null){
           this.domain = range;
           this.setLowerBound((int)Math.ceil(this.domain.getLowerBound()));
           this.setUpperBound((int)Math.floor(this.domain.getUpperBound()));
       }else{
           throw new IllegalArgumentException();
       }
   }

   @Override
   public synchronized void setLowerBound(int lowerBound) {
       if(lowerBound > this.upperBound){
           throw new IllegalArgumentException("lowerBound > upperBound");
       }
       this.lowerBound = lowerBound;
   }

   @Override
   public synchronized void setUpperBound(int upperBound) {
        if(upperBound < this.lowerBound){
            throw new IllegalArgumentException("upperBound < lowerBound");
        }
        this.upperBound = upperBound;
   }

   @Override
   public Paint getPaint(double value) {
     // Make sure that 'value' is within bounds
       value = Math.max(value, domain.getLowerBound());
       value = Math.min(value, domain.getUpperBound());

       // Calculate gray level
       int g = (int) ((value - domain.getLowerBound()) / (domain.getUpperBound() - domain.getLowerBound()) * 255.0);

       return new Color(g, g, g);
   }
}

